var items = $input.all();
var results = [];
var now = new Date().toISOString();

for (var i = 0; i < items.length; i++) {
  var html = items[i].json.data || items[i].json.body || '';
  if (typeof html !== 'string') html = JSON.stringify(html);

  // Extract course-like patterns from HTML
  // This is a basic extractor - enhance with specific selectors per source
  var titleMatches = html.match(/<h[1-4][^>]*>([^<]+)<\/h[1-4]>/gi) || [];
  var linkMatches = html.match(/href="([^"]*course[^"]*)"/gi) || [];

  for (var t = 0; t < titleMatches.length && t < 50; t++) {
    var title = titleMatches[t].replace(/<[^>]*>/g, '').trim();
    if (title.length > 5 && title.length < 200) {
      results.push({
        json: {
          entity_type: 'course',
          name: title,
          source_url: items[i].json.url || 'web-scrape',
          discovered_at: now,
          raw_data: { title: title, source_index: i }
        }
      });
    }
  }
}

// Deduplicate by name
var seen = {};
var unique = [];
for (var j = 0; j < results.length; j++) {
  var key = results[j].json.name.toLowerCase();
  if (!seen[key]) {
    seen[key] = true;
    unique.push(results[j]);
  }
}

return unique.length > 0 ? unique : [{ json: { entity_type: 'course', name: 'No new courses found this week', source_url: 'none', discovered_at: now, raw_data: {} } }];

var items = $input.all();
var allParsed = $('Parse Course Data').all();
var now = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

var html = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">';
html += '<h1 style="color:#2c3e50;">MyCourseMatchmaker - Weekly Course Report</h1>';
html += '<p style="color:#666;">' + now + ' &bull; ' + allParsed.length + ' courses processed</p><hr>';
html += '<h2>Courses Found This Week</h2><ul>';

for (var i = 0; i < allParsed.length && i < 50; i++) {
  html += '<li>' + allParsed[i].json.name + '</li>';
}
html += '</ul>';
html += '<hr><p style="color:#999;font-size:0.8em;">MyCourseMatchmaker Workhorse Scanner</p></div>';

return [{ json: { subject: 'MyCourseMatchmaker Weekly Report - ' + now, html: html } }];
